code_examples.code:
apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{ include "openmeter.componentName" (list . "charges-worker") }}
  labels:
    {{- include "openmeter.componentLabels" (list . "charges-worker") | nindent 4 }}
spec:
  replicas: {{ .Values.chargesWorker.replicaCount }}
  selector:
    matchLabels:
    {{- include "openmeter.componentSelectorLabels" (list . "charges-worker") | nindent 6 }}
  template:
    metadata:
      annotations:
        checksum/config: {{ include (print $.Template.BasePath "/configmap.yaml") . | sha256sum }}
      labels:
        {{- include "openmeter.componentLabels" (list . "charges-worker") | nindent 8 }}
    spec:
      serviceAccountName: {{ include "openmeter.serviceAccountName" . }}
      {{ if or .Values.postgresql.enabled .Values.clickhouse.enabled -}}
      initContainers:
        {{- if .Values.postgresql.enabled -}}
        {{- include "openmeter.init.postgres" (list .) | nindent 8 }}
        {{- end }}
      {{- end }}
      containers:
        - name: {{ .Chart.Name }}
          image: "{{ .Values.image.repository }}:{{ .Values.image.tag | default .Chart.AppVersion }}"
          command: ["/entrypoint.sh", "openmeter-charges-worker"]
          args: ["--telemetry-address", "0.0.0.0:10000", "--config", "/etc/openmeter/config.yaml"]
          ports:
            - name: telemetry-http
              containerPort: 10000
          livenessProbe:
            httpGet:
              path: /healthz/live
              port: telemetry-http
          readinessProbe:
            httpGet:
              path: /healthz/ready
              port: telemetry-http
          resources:
            {{- toYaml .Values.resources | nindent 12 }}
          volumeMounts:
            - name: config
              mountPath: /etc/openmeter
      volumes:
        - name: config
          configMap:
            name: {{ include "openmeter.fullname" . }}
